INSERT INTO `book` VALUES (213, '中共中央党史和文献研究院', '9787010211757', '《中国共产党简史》', 382, 42, '人民出版社', '2021-02-01 08:00:00.000000', 100, '无', '政治、法律', '/upload/eae1687ed02c4f51b21ec4d09bf9e45a.webp', '本书是中共中央党史和文献研究院为庆祝中国共产党成立100周年组织编写的简明党史读本，系统展现了中国共产党团结带领全国各族人民不懈奋斗的光辉历程。');
INSERT INTO `book` VALUES (214, '金冲及', '9787010096311', '《二十世纪中国史纲》', 1500, 198, '社会科学文献出版社', '2010-01-01 08:00:00.000000', 100, '无', '政治、法律', '/upload/redbook/20th_century_history.png', '全书以宏大的视野和严谨的考证，展现了20世纪中国从苦难走向辉煌的历史进程，是研究中国近现代史的经典著作。');
INSERT INTO `book` VALUES (215, '习近平', '9787010241352', '《论党的百年奋斗重大成就和历史经验》', 286, 49, '人民出版社', '2021-12-01 08:00:00.000000', 100, '无', '政治、法律', '/upload/redbook/party_100_years.png', '收录了习近平总书记关于党的百年奋斗重大成就和历史经验的重要论述，是学习党史的重要文献。');
INSERT INTO `book` VALUES (216, '罗广斌、杨益言', '9787020002500', '《红岩》', 592, 36, '人民文学出版社', '1961-12-01 08:00:00.000000', 100, '无', '文化、科学、教育、体育', '/upload/redbook/red_crag.png', '以重庆解放前夕的地下斗争为背景，展现了共产党人的崇高革命气节和英雄气概。');
INSERT INTO `book` VALUES (217, '吴强', '9787020090002', '《红日》', 484, 32, '人民文学出版社', '1957-01-01 08:00:00.000000', 100, '无', '文化、科学、教育、体育', '/upload/redbook/red_sun.png', '描写了解放战争时期华东野战军在山东战场歼灭国民党王牌部队的战斗历程。');
INSERT INTO `book` VALUES (218, '曲波', '9787020002203', '《林海雪原》', 473, 35, '人民文学出版社', '1957-09-01 08:00:00.000000', 100, '无', '文化、科学、教育、体育', '/upload/redbook/forest_snowfield.png', '讲述了东北民主联军一支小分队，在团参谋长少剑波的率领下，深入林海雪原执行剿匪任务的故事。');
INSERT INTO `book` VALUES (219, '柳青', '9787020096567', '《创业史》', 480, 45, '人民文学出版社', '1960-06-01 08:00:00.000000', 100, '无', '文化、科学、教育、体育', '/upload/redbook/entrepreneurial_history.png', '以梁生宝互助组的发展为线索，展现了中国农村社会主义改造时期的社会风貌和农民思想观念的转变。');
INSERT INTO `book` VALUES (220, '埃德加·斯诺', '9787020096802', '《红星照耀中国》（西行漫记）', 400, 42, '人民文学出版社', '2016-06-01 08:00:00.000000', 100, '董乐山', '政治、法律', '/upload/redbook/red_star_over_china.png', '美国记者埃德加·斯诺深入陕北革命根据地的纪实报道，首次向世界全面介绍中国工农红军和中国共产党的真实情况。');
INSERT INTO `book` VALUES (221, '王树增', '9787020050809', '《长征》', 806, 68, '人民文学出版社', '2006-09-01 08:00:00.000000', 99, '无', '政治、法律', '/upload/redbook/long_march.png', '全景式展现了中国工农红军二万五千里长征的壮丽史诗，是描写长征的经典纪实文学作品。');
INSERT INTO `book` VALUES (222, '聂荣臻', '9787506506111', '《聂荣臻回忆录》', 678, 58, '解放军出版社', '1984-10-01 08:00:00.000000', 100, '无', '政治、法律', '/upload/redbook/nie_ruizhen_memoirs.png', '聂荣臻元帅的个人回忆录，记录了他从参加革命到新中国成立后的亲身经历，具有重要的史料价值。');
INSERT INTO `book` VALUES (223, '何虎生', '9787010234118', '《中国共产党百年简史》', 420, 58, '人民出版社', '2021-06-01 08:00:00.000000', 100, '无', '政治、法律', '/upload/redbook/party_100_brief.png', '简明扼要地讲述了中国共产党百年奋斗的光辉历程、伟大成就和宝贵经验。');
INSERT INTO `book` VALUES (224, '李忠杰', '9787509858067', '《党史必修课》', 468, 59.8, '中共党史出版社', '2021-03-01 08:00:00.000000', 100, '无', '政治、法律', '/upload/redbook/party_history_course.png', '以专题形式解读党史重大事件和重要人物，是党员干部学习党史的优秀辅导读物。');
INSERT INTO `book` VALUES (225, '中共中央宣传部', '9787010232039', '《中国共产党宣传工作简史》', 756, 86, '人民出版社', '2022-01-01 08:00:00.000000', 100, '无', '政治、法律', '/upload/7a941d22e645418ab2476321dfdaaecf.webp', '系统总结了中国共产党宣传工作的百年历程和宝贵经验，展现了党的宣传工作的优良传统。');
